\\$response = Invoke-WebRequest -Uri 'http://localhost:8090' -UseBasicParsing -TimeoutSec 10 -ErrorAction SilentlyContinue
if \(\\$response\) { Write-Host 'HTTP' \\$response.StatusCode; \\$response.Content.Substring\(0, [Math]::Min\(200, \\$response.Content.Length\)\) }
else { Write-Host 'No response' }
" 2>&1)
